import{_ as o,o as i,c as s,ai as a}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Voice Overlay","description":"","frontmatter":{"summary":"Voice overlay lifecycle when wake-word and push-to-talk overlap","read_when":["Adjusting voice overlay behavior"],"title":"Voice Overlay"},"headers":[],"relativePath":"platforms/mac/voice-overlay.md","filePath":"platforms/mac/voice-overlay.md","lastUpdated":1771906665000}'),t={name:"platforms/mac/voice-overlay.md"};function l(d,e,c,n,r,h){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="voice-overlay-lifecycle-macos" tabindex="-1"><a class="header-anchor" href="#voice-overlay-lifecycle-macos">#</a> Voice Overlay Lifecycle (macOS)</h1><p>Audience: macOS app contributors. Goal: keep the voice overlay predictable when wake-word and push-to-talk overlap.</p><h2 id="current-intent" tabindex="-1"><a class="header-anchor" href="#current-intent">#</a> Current intent</h2><ul><li>If the overlay is already visible from wake-word and the user presses the hotkey, the hotkey session <em>adopts</em> the existing text instead of resetting it. The overlay stays up while the hotkey is held. When the user releases: send if there is trimmed text, otherwise dismiss.</li><li>Wake-word alone still auto-sends on silence; push-to-talk sends immediately on release.</li></ul><h2 id="implemented-dec-9-2025" tabindex="-1"><a class="header-anchor" href="#implemented-dec-9-2025">#</a> Implemented (Dec 9, 2025)</h2><ul><li>Overlay sessions now carry a token per capture (wake-word or push-to-talk). Partial/final/send/dismiss/level updates are dropped when the token doesn’t match, avoiding stale callbacks.</li><li>Push-to-talk adopts any visible overlay text as a prefix (so pressing the hotkey while the wake overlay is up keeps the text and appends new speech). It waits up to 1.5s for a final transcript before falling back to the current text.</li><li>Chime/overlay logging is emitted at <code>info</code> in categories <code>voicewake.overlay</code>, <code>voicewake.ptt</code>, and <code>voicewake.chime</code> (session start, partial, final, send, dismiss, chime reason).</li></ul><h2 id="next-steps" tabindex="-1"><a class="header-anchor" href="#next-steps">#</a> Next steps</h2><ol><li><strong>VoiceSessionCoordinator (actor)</strong><ul><li>Owns exactly one <code>VoiceSession</code> at a time.</li><li>API (token-based): <code>beginWakeCapture</code>, <code>beginPushToTalk</code>, <code>updatePartial</code>, <code>endCapture</code>, <code>cancel</code>, <code>applyCooldown</code>.</li><li>Drops callbacks that carry stale tokens (prevents old recognizers from reopening the overlay).</li></ul></li><li><strong>VoiceSession (model)</strong><ul><li>Fields: <code>token</code>, <code>source</code> (wakeWord|pushToTalk), committed/volatile text, chime flags, timers (auto-send, idle), <code>overlayMode</code> (display|editing|sending), cooldown deadline.</li></ul></li><li><strong>Overlay binding</strong><ul><li><code>VoiceSessionPublisher</code> (<code>ObservableObject</code>) mirrors the active session into SwiftUI.</li><li><code>VoiceWakeOverlayView</code> renders only via the publisher; it never mutates global singletons directly.</li><li>Overlay user actions (<code>sendNow</code>, <code>dismiss</code>, <code>edit</code>) call back into the coordinator with the session token.</li></ul></li><li><strong>Unified send path</strong><ul><li>On <code>endCapture</code>: if trimmed text is empty → dismiss; else <code>performSend(session:)</code> (plays send chime once, forwards, dismisses).</li><li>Push-to-talk: no delay; wake-word: optional delay for auto-send.</li><li>Apply a short cooldown to the wake runtime after push-to-talk finishes so wake-word doesn’t immediately retrigger.</li></ul></li><li><strong>Logging</strong><ul><li>Coordinator emits <code>.info</code> logs in subsystem <code>ai.opensoul</code>, categories <code>voicewake.overlay</code> and <code>voicewake.chime</code>.</li><li>Key events: <code>session_started</code>, <code>adopted_by_push_to_talk</code>, <code>partial</code>, <code>finalized</code>, <code>send</code>, <code>dismiss</code>, <code>cancel</code>, <code>cooldown</code>.</li></ul></li></ol><h2 id="debugging-checklist" tabindex="-1"><a class="header-anchor" href="#debugging-checklist">#</a> Debugging checklist</h2><ul><li><p>Stream logs while reproducing a sticky overlay:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stream</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --predicate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;subsystem == &quot;ai.opensoul&quot; AND category CONTAINS &quot;voicewake&quot;&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --level</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --style</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compact</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Verify only one active session token; stale callbacks should be dropped by the coordinator.</p></li><li><p>Ensure push-to-talk release always calls <code>endCapture</code> with the active token; if text is empty, expect <code>dismiss</code> without chime or send.</p></li></ul><h2 id="migration-steps-suggested" tabindex="-1"><a class="header-anchor" href="#migration-steps-suggested">#</a> Migration steps (suggested)</h2><ol><li>Add <code>VoiceSessionCoordinator</code>, <code>VoiceSession</code>, and <code>VoiceSessionPublisher</code>.</li><li>Refactor <code>VoiceWakeRuntime</code> to create/update/end sessions instead of touching <code>VoiceWakeOverlayController</code> directly.</li><li>Refactor <code>VoicePushToTalk</code> to adopt existing sessions and call <code>endCapture</code> on release; apply runtime cooldown.</li><li>Wire <code>VoiceWakeOverlayController</code> to the publisher; remove direct calls from runtime/PTT.</li><li>Add integration tests for session adoption, cooldown, and empty-text dismissal.</li></ol>',12)])])}const k=o(t,[["render",l]]);export{u as __pageData,k as default};
